#include <iostream>using namespace std; int solve(string str, int n){      int ans = 0;       int one=0;      int zero=0;      for(auto &i:str)      {            if(i=='1')            {                  one++;            }            else{                  zero++;            }      }      for(int i=0;i<zero;i++)      {             if(str[i]=='1')            {                  ans++;            }      }           return ans;} int main(){       int t;      cin >> t;       while (t-- > 0)      {            int n;            cin >> n;            string str;            cin >> str;             cout << solve(str, n) << endl;      }       return 0;}